const vMFindByServerID = `-- name: VMFindByServerID :many
SELECT id, server_id, image_id, status, vcpus, memory, ip_address, port, env_variables, deleted_at, created_at, updated_at FROM vms WHERE server_id = $1 AND deleted_at IS NULL
`

func (q *Queries) VMFindByServerID(ctx context.Context, serverID pgtype.UUID) ([]Vm, error) {
	rows, err := q.db.Query(ctx, vMFindByServerID, serverID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Vm{}
	for rows.Next() {
		var i Vm
		if err := rows.Scan(
			&i.ID,
			&i.ServerID,
			&i.ImageID,
			&i.Status,
			&i.Vcpus,
			&i.Memory,
			&i.IpAddress,
			&i.Port,
			&i.EnvVariables,
			&i.DeletedAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

